"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[5811],{2792(e,o,t){t.r(o),t.d(o,{assets:()=>h,contentTitle:()=>r,default:()=>c,frontMatter:()=>i,metadata:()=>s,toc:()=>d});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-24","title":"Discourses \u2014 Book 1, Chapter 24","description":"Book 1 \u2014 Chapter 24","source":"@site/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-24.md","sourceDirName":"stoicism/epictetus/discourses/book-1","slug":"/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-24","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-24","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":24,"frontMatter":{"sidebar_position":24,"title":"Discourses \u2014 Book 1, Chapter 24","sidebar_label":"Book 1, Ch. 24"},"sidebar":"philosophersSidebar","previous":{"title":"Book 1, Ch. 23","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-23"},"next":{"title":"Book 1, Ch. 25","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-25"}}');var n=t(4848),a=t(8453);const i={sidebar_position:24,title:"Discourses \u2014 Book 1, Chapter 24",sidebar_label:"Book 1, Ch. 24"},r="Discourses",h={},d=[{value:"Book 1 \u2014 Chapter 24",id:"book-1--chapter-24",level:2},{value:"How One Should Contend Against Difficulties",id:"how-one-should-contend-against-difficulties",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function l(e){const o={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,a.R)(),...e.components},{Details:t}=o;return t||function(e,o){throw new Error("Expected "+(o?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,n.jsxs)(n.Fragment,{children:[(0,n.jsxs)("div",{style:{textAlign:"center"},children:[(0,n.jsx)(o.header,{children:(0,n.jsx)(o.h1,{id:"discourses",children:"Discourses"})}),(0,n.jsx)(o.h2,{id:"book-1--chapter-24",children:"Book 1 \u2014 Chapter 24"}),(0,n.jsx)(o.h3,{id:"how-one-should-contend-against-difficulties",children:"How One Should Contend Against Difficulties"})]}),"\n",(0,n.jsx)(o.p,{children:(0,n.jsx)(o.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,n.jsxs)(t,{open:!0,children:[(0,n.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,n.jsx)(o.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,n.jsx)(o.p,{children:"Difficulties are the training ground, not an interruption of it. God is the trainer, you are the athlete, and the crisis is the contest. The right scout \u2014 Diogenes \u2014 comes back from reconnaissance reporting that death is not evil, that glory is noise, that poverty and hardship are manageable. The wrong scout comes back panicking and warning everyone to flee."}),(0,n.jsx)(o.p,{children:"The chapter's other key image: when you disembark a ship, you don't take the helm. You take what's yours \u2014 the oil-flask, the wallet. Apply this everywhere. Nothing the emperor can strip away was ever truly yours. Kings and emperors are the proper subjects of tragedy \u2014 their crowns come first, then Sophocles. The poor man doesn't even get a solo part; he's in the chorus, and that's fine."}),(0,n.jsx)(o.p,{children:"The door is always open. Don't stay and moan. When the game stops being worth playing, do what children do: say so, and leave."})]}),"\n",(0,n.jsxs)(t,{open:!0,children:[(0,n.jsx)("summary",{children:"Text"}),(0,n.jsx)(o.h2,{id:"text",children:"Text"}),(0,n.jsx)(o.p,{children:"DIFFICULTIES are what show men's character. Therefore when a difficult crisis meets you, remember that you are as the raw youth with whom God the trainer is wrestling."}),(0,n.jsx)(o.p,{children:"'To what end?' the hearer asks."}),(0,n.jsx)(o.p,{children:"That you may win at Olympia: and that cannot be done without sweating for it. To my mind no man's difficulties ever gave him a finer trial than yours, if only you will use them for exercise, as the athlete wrestles with the young man. Even now we are sending you to Rome to spy out the land:  and no one sends a coward as a spy, for that means that if he but hears a noise or sees a shadow anywhere, he will come running in confusion and saying that the enemy are close at hand. So now if you come and tell us 'The doings in Rome are fearful, death is terrible, exile is terrible, evil-speaking is terrible, poverty is terrible: fly sirs, the enemy is at hand', we shall say to you, 'Begone, prophesy to yourself, the only mistake we made was in sending a man like you to spy out the land'. Diogenes, who was sent scouting before you, has brought us back a different report: he says, 'Death is not evil, for it is not dishonour'; he says, 'Glory is a vain noise made by madmen'. And what a message this scout brought us about pain and pleasure and poverty! 'To wear no raiment', he says, 'is better than any robe with purple hem'; 'to sleep on the ground without a bed', he says, 'is the softest couch.' Moreover he proves each point by showing his own confidence, his tranquillity of mind, his freedom, and withal his body well knit, and in good condition. 'No enemy is near,' he says, 'all is full of peace.'"}),(0,n.jsx)(o.p,{children:"What do you mean, Diogenes?"}),(0,n.jsx)(o.p,{children:"'See,' he says, 'have I suffered shot or wound or rout?'"}),(0,n.jsx)(o.p,{children:"That is the right kind of scouting: but you come back to us and talk at random. Drop your cowardice and go back again, and take a more accurate observation."}),(0,n.jsx)(o.p,{children:"What am I to do then?"}),(0,n.jsx)(o.p,{children:"What do you do, when you disembark from a ship? Do you take the helm and the oars with you? What do you take then? You take what is yours, oil-flask and wallet. So now if you remember what is yours, you will never claim what is another's."}),(0,n.jsx)(o.p,{children:"The emperor says to you, 'Lay aside your purple hem.'"}),(0,n.jsx)(o.p,{children:"See, I wear the narrow one."}),(0,n.jsx)(o.p,{children:"'Lay aside this also.'"}),(0,n.jsx)(o.p,{children:"See, I wear the toga only."}),(0,n.jsx)(o.p,{children:"'Lay aside the toga.'"}),(0,n.jsx)(o.p,{children:"See, I take that off too."}),(0,n.jsx)(o.p,{children:"'Ay, but you still rouse my envy.'"}),(0,n.jsx)(o.p,{children:"Then take my poor body, every bit of it. The man to whom I can throw away my body has no fears for me."}),(0,n.jsx)(o.p,{children:"'But he will not leave me as his heir.'"}),(0,n.jsx)(o.p,{children:"What? Did I forget that none of these things was mine? In what sense do we call them 'mine'? Only as we call 'mine' the pallet in an inn. If then the inn-keeper dies and leaves you the pallets, well and good; if he leaves them to another, that man will have them, and you will look for another. If you do not find one you will sleep on the ground, only do so with a good cheer, snoring the while, and remembering that it is among rich men and kings and emperors that tragedies find room, and that no poor man fills a part in a tragedy except as one of the chorus. But kings begin with a prelude of good things:"}),(0,n.jsx)(o.p,{children:"Crown high the halls"}),(0,n.jsx)(o.p,{children:"[Author unknown]"}),(0,n.jsx)(o.p,{children:"and then about the third or fourth act comes--"}),(0,n.jsx)(o.p,{children:"O Cithaeron, why didst thou receive me?"}),(0,n.jsx)(o.p,{children:"[Sophocles, Oedipus the King, 1391]"}),(0,n.jsx)(o.p,{children:"[paragraph continues] Poor slave, where are your crowns, where your diadem? Your guards avail you naught. Therefore when you come near to one of those great men remember this, that you are meeting a tragic character, no actor, but Oedipus in person."}),(0,n.jsx)(o.p,{children:"'Nay, but such a one is blessed, for he has a great company to walk with him.'"}),(0,n.jsx)(o.p,{children:"I too join the ranks of the multitude and have a large company to walk with."}),(0,n.jsx)(o.p,{children:"To sum up: remember that the door is open. Do not be a greater coward than the children, but do as they do. Children, when things do not please them, say, 'I will not play any more'; so, when things seem to you to reach that point, just say, 'I will not play any more,' and so depart, instead of staying to make moan."})]})]})}function c(e={}){const{wrapper:o}={...(0,a.R)(),...e.components};return o?(0,n.jsx)(o,{...e,children:(0,n.jsx)(l,{...e})}):l(e)}},8453(e,o,t){t.d(o,{R:()=>i,x:()=>r});var s=t(6540);const n={},a=s.createContext(n);function i(e){const o=s.useContext(a);return s.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function r(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:i(e.components),s.createElement(a.Provider,{value:o},e.children)}}}]);